"const fs = require('fs');
const path = require('path');

const filePath = path.join(__dirname, 'gamenest-hub', 'src', 'data', 'games.ts');
let content = fs.readFileSync(filePath, 'utf8');

// 1. Add downloadUrl to the Game interface
content = content.replace(
  'cardHeight: "small" | "medium" | "large";',
  'cardHeight: "small" | "medium" | "large";\n  downloadUrl: string;'
);

// 2. Add downloadUrl to each of the 21 games in the array.
// Start replacing after the interface declaration.
const splitIndex = content.indexOf('export const games: Game[] = [');
if (splitIndex === -1) {
  throw new Error('Could not find start of games array');
}

let header = content.substring(0, splitIndex);
let arrayPart = content.substring(splitIndex);

let gameIndex = 1;
arrayPart = arrayPart.replace(/cardHeight:\s*"(small|medium|large)"/g, (match, p1) => {
  const result = `cardHeight: "${p1}",\n    downloadUrl: "https://example.com/download-box${gameIndex}"`;
  gameIndex++;
  return result;
});

content = header + arrayPart;

fs.writeFileSync(filePath, content, 'utf8');
console.log('Successfully updated games.ts with downloadUrl properties!');
"
